import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { IoIosHeartEmpty, IoIosHeart } from 'react-icons/io';
import axios from "axios";
import { ProductImageGallery } from '../../pages/ProductDIscountSection/ProductDIscountSection';
import { toast } from 'react-toastify';
import { useTranslation } from "react-i18next";

export default function ProductCard({ 
  item, 
  getProductHaveDiscount = () => {}, 
  getFav = () => {}, 
  infavoritesPage = false,
  fav = false
}) {
  const { i18n } = useTranslation();
  const isRTL = i18n.language === "ar";
  const [isFavorite, setIsFavorite] = useState(item?.is_fav || infavoritesPage);
  const [token, setToken] = useState(null);
  const [isLoadingFavorite, setIsLoadingFavorite] = useState(false);

  useEffect(() => {
    setToken(localStorage.getItem('token'));
  }, [i18n.language]);

  const toggleFavorite = async (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (!token) {
      toast.info(isRTL ? "يرجى تسجيل الدخول أولاً" : "Please login first");
      return;
    }
    if (isLoadingFavorite) return;
    setIsLoadingFavorite(true);
    try {
      const response = await axios.post(
        `${process.env.REACT_APP_API_BASE_URL}/api/favorites/toggle`,
        { product_id: item?.id },
        { headers: { Accept: "application/json", "Accept-Language": i18n.language, "Authorization": `Bearer ${token}` } }
      );
      if (response.status === 200) {
        setIsFavorite(!isFavorite);
        toast.success(!isFavorite
          ? (isRTL ? "تمت الإضافة إلى المفضلة" : "Added to favourites")
          : (isRTL ? "تمت الإزالة من المفضلة" : "Removed from favourites")
        );
        getProductHaveDiscount();
        getFav();
      }
    } catch (error) {
      toast.error(isRTL ? "فشل في تحديث المفضلة" : "Failed to update favorites");
    } finally {
      setIsLoadingFavorite(false);
    }
  };

  const discount = item?.discount > 0 ? item.discount :
    (item?.price_before && item?.price_after && item.price_before > item.price_after
      ? Math.round(((item.price_before - item.price_after) / item.price_before) * 100)
      : 0);

  return (
    <motion.div
      className="overflow-hidden position-relative bg-white"
      style={{
        borderRadius: '12px',
        border: '1px solid #f0f0f0',
        boxShadow: '0 1px 8px rgba(0,0,0,0.06)',
        cursor: 'pointer',
      }}
      layout
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ type: "spring", stiffness: 300 }}
      whileHover={{ y: -4, boxShadow: '0 8px 24px rgba(0,0,0,0.11)', transition: { type: "spring", stiffness: 400 } }}
    >
      {/* Discount Badge */}
      {discount > 0 && (
        <div style={{
          position: 'absolute', top: '10px',
          left: isRTL ? 'auto' : '10px',
          right: isRTL ? '10px' : 'auto',
          zIndex: 3,
          background: '#dc2626',
          color: '#fff',
          fontSize: '11px',
          fontWeight: '800',
          padding: '3px 8px',
          borderRadius: '6px',
        }}>
          {discount}%
        </div>
      )}

      {/* Heart Button */}
      <button
        onClick={toggleFavorite}
        style={{
          position: 'absolute',
          top: '10px',
          right: isRTL ? 'auto' : '10px',
          left: isRTL ? '10px' : 'auto',
          zIndex: 3,
          background: 'rgba(255,255,255,0.92)',
          border: 'none',
          borderRadius: '50%',
          width: '32px', height: '32px',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          cursor: 'pointer',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          padding: 0,
        }}
      >
        {isFavorite || infavoritesPage
          ? <IoIosHeart style={{ fontSize: '17px', color: '#dc2626' }} />
          : <IoIosHeartEmpty style={{ fontSize: '17px', color: '#999' }} />
        }
      </button>

      {/* Product Image */}
      <Link to={`/productdetails/${item?.id}`} style={{ textDecoration: 'none', display: 'block' }}>
        <div style={{
          background: '#fafafa',
          height: '180px',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          overflow: 'hidden', padding: '8px',
          borderBottom: '1px solid #f5f5f5',
        }}>
          <ProductImageGallery images={item?.images} productName={item?.name} />
        </div>
      </Link>

      {/* Card Body */}
      <Link to={`/productdetails/${item?.id}`} style={{ textDecoration: 'none', color: 'inherit', display: 'block' }}>
        <div style={{ padding: '12px' }}>

          {/* Product Name */}
          <p style={{
            fontSize: '13px', fontWeight: '600', color: '#111',
            margin: '0 0 6px', lineHeight: '1.45',
            display: '-webkit-box', WebkitLineClamp: 2,
            WebkitBoxOrient: 'vertical', overflow: 'hidden',
          }}>
            {item?.name}
          </p>

          {/* Category */}
          {item?.category && (
            <span style={{
              fontSize: '10px', fontWeight: '700',
              color: '#dc2626', background: '#fff5f5',
              padding: '2px 7px', borderRadius: '4px',
              display: 'inline-block', marginBottom: '8px',
            }}>
              {item.category}
            </span>
          )}

          {/* Brand */}
          {item?.brand && (
            <span style={{
              fontSize: '10px', color: '#888', fontWeight: '600',
              display: 'block', marginBottom: '6px',
            }}>
              {item.brand}
            </span>
          )}

          {/* Price */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px', flexWrap: 'wrap' }}>
            <span style={{ fontSize: '15px', fontWeight: '800', color: '#dc2626' }}>
              {item?.price_after} {isRTL ? "ج.م" : "EGP"}
            </span>
            {item?.price_before && item.price_before !== item.price_after && (
              <span style={{ fontSize: '12px', color: '#aaa', textDecoration: 'line-through', fontWeight: '400' }}>
                {item?.price_before} {isRTL ? "ج.م" : "EGP"}
              </span>
            )}
          </div>
        </div>
      </Link>

      {/* Fav Page Button */}
      {fav && (
        <div style={{ padding: '0 12px 12px' }}>
          <button
            onClick={toggleFavorite}
            style={{
              width: '100%', padding: '8px',
              borderRadius: '8px', border: 'none', cursor: 'pointer',
              fontSize: '13px', fontWeight: '700',
              background: (isFavorite || infavoritesPage) ? '#dc2626' : '#fff5f5',
              color: (isFavorite || infavoritesPage) ? '#fff' : '#dc2626',
              transition: 'all 0.2s ease',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px',
            }}
          >
            {(isFavorite || infavoritesPage)
              ? <><IoIosHeart /> {isRTL ? "إزالة من المفضلة" : "Remove from favourites"}</>
              : <><IoIosHeartEmpty /> {isRTL ? "إضافة إلى المفضلة" : "Add to favourites"}</>
            }
          </button>
        </div>
      )}
    </motion.div>
  );
}
